# ── Core logic ─────────────────────────────────────────────
def portfolio_return(w1,r1,r2):   return w1*r1+(1-w1)*r2
def portfolio_sd(w1,sd1,sd2,rho):
    return np.sqrt(w1**2*sd1**2+(1-w1)**2*sd2**2+2*rho*w1*(1-w1)*sd1*sd2)
def portfolio_esg(w1,e1,e2):       return w1*e1+(1-w1)*e2
def convert_to_100(score,agency):
    agency=agency.lower()
    try:
        if agency=="sustainalytics":
            s=float(score);return max(0.,min(100.,100-(s/50)*100)) if s<50 else 0.
        elif agency=="msci":
            m={"ccc":0.,"b":16.7,"bb":33.4,"bbb":50.1,"a":66.8,"aa":83.5,"aaa":100.}
            return m.get(str(score).strip().lower(),0.)
        elif agency=="refinitiv":
            r={0:0.,1:10.,2:25.,3:50.,4:75.,5:95.};return r.get(int(float(score)),0.)
        elif agency=="s&p":return max(0.,min(100.,float(score)))
    except:return 0.
    return 0.

def esg_hex(score):
    score=max(0.,min(100.,score))
    if score<=50:
        t=score/50.;r=239;g=int(68+t*(180-68));b=int(68+t*(8-68))
    else:
        t=(score-50)/50.;r=int(234+t*(34-234));g=int(180+t*(197-180));b=int(8+t*(94-8))
    return f"#{r:02x}{g:02x}{b:02x}"

def progress_ring_html(score,subtitle="ESG Score",size=200,glow=True):
    col=esg_hex(score);R=52;circ=2*np.pi*R;dash=(score/100)*circ;gap=circ-dash
    shadow=f'filter:drop-shadow(0 0 12px {col}55);' if glow else ''
    return f"""<div style="display:flex;flex-direction:column;align-items:center;gap:8px;padding:8px 0;{shadow}">
      <svg width="{size}" height="{size}" viewBox="0 0 120 120">
        <circle cx="60" cy="60" r="{R}" fill="none" stroke="{col}22" stroke-width="13"/>
        <circle cx="60" cy="60" r="{R}" fill="none" stroke="{col}" stroke-width="13"
                stroke-dasharray="{dash:.2f} {gap:.2f}" stroke-linecap="round"
                transform="rotate(-90 60 60)"/>
        <text x="60" y="51" text-anchor="middle" font-family="Inter,sans-serif"
              font-size="20" font-weight="700" fill="{col}">{score:.1f}</text>
        <text x="60" y="67" text-anchor="middle" font-family="Inter,sans-serif"
              font-size="10" fill="#94a3b8">/ 100</text>
      </svg>
      <span style="font-size:11px;font-weight:700;letter-spacing:0.1em;
                   text-transform:uppercase;color:#7a9a8a;">{subtitle}</span>
    </div>"""

def alloc_bar_html(w1,w2,n1,n2):
    p1=f"{w1*100:.1f}%";p2=f"{w2*100:.1f}%"
    return f"""<div class="bar-row">
      <div class="bar-label-row"><span style="color:#52c98a;">{n1}</span><span style="color:#52c98a;">{p1}</span></div>
      <div class="bar-track"><div class="bar-fill-green" style="width:{p1};"></div></div>
    </div><div class="bar-row" style="margin-top:14px;">
      <div class="bar-label-row"><span style="color:#3b82f6;">{n2}</span><span style="color:#3b82f6;">{p2}</span></div>
      <div class="bar-track"><div class="bar-fill-blue" style="width:{p2};"></div></div>
    </div>"""

def alloc_card_html(title,w1,w2,n1,n2):
    p1=f"{w1*100:.1f}%";p2=f"{w2*100:.1f}%"
    return f"""<div class="mini-card">
      <div class="mini-card-title">{title}</div>
      <div class="bar-row"><div class="bar-label-row"><span style="color:#52c98a;">{n1}</span><span style="color:#52c98a;">{p1}</span></div>
      <div class="bar-track"><div class="bar-fill-green" style="width:{p1};"></div></div></div>
      <div class="bar-row" style="margin-top:10px;"><div class="bar-label-row"><span style="color:#3b82f6;">{n2}</span><span style="color:#3b82f6;">{p2}</span></div>
      <div class="bar-track"><div class="bar-fill-blue" style="width:{p2};"></div></div></div>
    </div>"""

def metric_tile(label,value,sub=""):
    s=f'<div class="sub">{sub}</div>' if sub else ""
    return f'<div class="metric-tile"><div class="label">{label}</div><div class="value">{value}</div>{s}</div>'

def delta_card(label,value,suffix,decimals=2,flip=False):
    """flip=True means negative is good (e.g. risk reduction)."""
    is_pos = value > 0.001
    is_neg = value < -0.001
    good   = (is_pos and not flip) or (is_neg and flip)
    bad    = (is_neg and not flip) or (is_pos and flip)
    if good:
        arrow="▲"; cls="delta-arrow-pos"; val_str=f"+{abs(value):.{decimals}f}{suffix}"
    elif bad:
        arrow="▼"; cls="delta-arrow-neg"; val_str=f"−{abs(value):.{decimals}f}{suffix}"
    else:
        arrow="—"; cls="delta-arrow-neu"; val_str=f"0{suffix}"
    return f"""<div class="delta-card">
      <div class="delta-label">{label}</div>
      <div class="{cls}">{arrow} {val_str}</div>
      <div class="delta-sub">vs unconstrained</div>
    </div>"""

def field_label(text):
    st.markdown(f'<div class="field-label">{text}</div>',unsafe_allow_html=True)

def section_kicker(text):
    st.markdown(f'<div class="section-kicker">{text}</div>',unsafe_allow_html=True)

def get_agency_input(name,agency,key_pref):
    if agency=="MSCI":
        val=st.selectbox(f"{name} MSCI Rating",["CCC","B","BB","BBB","A","AA","AAA"],index=3,key=f"{key_pref}_m")
    elif agency=="Refinitiv":
        val=st.number_input(f"{name} Score (0–5)",0,5,3,key=f"{key_pref}_r")
    else:
        val=st.number_input(f"{name} Score",value=50.0,key=f"{key_pref}_s")
    return convert_to_100(val,agency)

def gamma_label(g):
    if g>=7:    return "Very Cautious"
    elif g>=3:  return "Cautious"
    elif g>=-2: return "Moderate"
    elif g>=-6: return "Adventurous"
    else:       return "Very Adventurous"

def esg_profile_from_lambda(lam):
    if   lam<=0.10: return "Return-focused",      "Very little willingness to trade return for ESG."
    elif lam<=0.35: return "Light ESG preference", "Some ESG interest, returns remain the priority."
    elif lam<=0.65: return "Balanced investor",    "Willing to trade a moderate amount of return for ESG."
    elif lam<=0.88: return "ESG-led investor",     "Strong ESG priority; accepts a meaningful return trade-off."
    else:           return "Impact-focused",       "Maximum ESG emphasis; return is secondary."

def dark_chart_style(ax,fig):
    """Apply dark theme to a matplotlib figure."""
    bg="#0e1014"
    fig.patch.set_facecolor(bg); ax.set_facecolor(bg)
    ax.tick_params(colors="#8b93a3",labelsize=9)
    ax.xaxis.label.set_color("#8b93a3"); ax.yaxis.label.set_color("#8b93a3")
    ax.title.set_color("#e7eaf0")
    ax.spines["bottom"].set_color("#2a2f3a")
    ax.spines["left"].set_color("#2a2f3a")
    for sp in ["top","right"]: ax.spines[sp].set_visible(False)
    ax.grid(True,alpha=0.1,linestyle="--",color="#ffffff")


# ── Progress stepper ───────────────────────────────────────
def render_progress(current_stage):
    cols=st.columns(len(STAGES),gap="small")
    for i,(col,label) in enumerate(zip(cols,STAGES),start=1):
        state="done" if i<current_stage else ("active" if i==current_stage else "todo")
        bg   ="rgba(82,201,138,0.16)" if state=="active" else ("rgba(82,201,138,0.10)" if state=="done" else "rgba(255,255,255,0.03)")
        brd  ="rgba(82,201,138,0.55)" if state!="todo"   else "rgba(255,255,255,0.10)"
        clr  ="#52c98a"               if state!="todo"   else "#525a69"
        glow ="0 0 0 5px rgba(82,201,138,0.08)" if state=="active" else "none"
        icon ="✓"                     if state=="done"   else str(i)
        with col:
            st.markdown(f"""
            <div style="text-align:center;">
              <div style="width:32px;height:32px;border-radius:999px;margin:0 auto 7px;
                          display:flex;align-items:center;justify-content:center;
                          font-size:12px;font-weight:700;
                          background:{bg};border:1px solid {brd};color:{clr};box-shadow:{glow};">{icon}</div>
              <div style="font-size:9px;letter-spacing:0.12em;text-transform:uppercase;
                          font-weight:700;color:{clr};line-height:1.35;">{label}</div>
            </div>""",unsafe_allow_html=True)

# ── Summary strip ──────────────────────────────────────────
def render_summary():
    s=st.session_state.stage
    if s<2: return
    n1=safe_name("asset1_name","Asset 1")
    n2=safe_name("asset2_name","Asset 2")
    g=st.session_state.get("gamma_label","—")
    esg=st.session_state.get("pref_label","—")
    items=[
        f'<div class="summary-item"><div class="summary-dot"></div><span>Asset 1: <strong>{n1}</strong></span></div>',
        f'<div class="summary-item"><div class="summary-dot"></div><span>Asset 2: <strong>{n2}</strong></span></div>',
    ]
    if s>=3: items.append(f'<div class="summary-item"><div class="summary-dot"></div><span>Risk: <strong>{g}</strong></span></div>')
    if s>=4: items.append(f'<div class="summary-item"><div class="summary-dot"></div><span>ESG: <strong>{esg}</strong></span></div>')
    st.markdown(f'<div class="summary-strip">{"".join(items)}</div>',unsafe_allow_html=True)

